SELECT Customer.No_ AS CustomerCheckCode, Customer.Name AS CustomerName, [Sales Header].[Shortcut Dimension 2 Code] AS Marchio, [Sales Header].[SELLING SEASON CODE], [Sales Header].[Document Date] AS [Data Ordine], IIf(InStr([business e-mail],";")<>0,Left$([BUSINESS E-MAIL],InStr([BUSINESS E-MAIL],";")-1),[BUSINESS E-MAIL]) AS [Business E-Mail_], [Geographical Zone].Description AS Geo1Desc, [Geographical Zone_1].Description AS Geo2Desc
FROM [Sales Header] INNER JOIN ((Customer LEFT JOIN [Geographical Zone] ON Customer.[Geographical Zone] = [Geographical Zone].Code) LEFT JOIN [Geographical Zone] AS [Geographical Zone_1] ON Customer.[Geographical Zone 2] = [Geographical Zone_1].Code) ON [Sales Header].[Sell-to Customer No_] = Customer.No_
GROUP BY Customer.No_, Customer.Name, [Sales Header].[Shortcut Dimension 2 Code], [Sales Header].[SELLING SEASON CODE], [Sales Header].[Document Date], IIf(InStr([business e-mail],";")<>0,Left$([BUSINESS E-MAIL],InStr([BUSINESS E-MAIL],";")-1),[BUSINESS E-MAIL]), [Geographical Zone].Description, [Geographical Zone_1].Description, [Sales Header].[Document Type], [Sales Header].[ORDER TYPE]
HAVING ((([Sales Header].[SELLING SEASON CODE])=[FiltroStagioneVendita]) AND ((IIf(InStr([business e-mail],";")<>0,Left$([BUSINESS E-MAIL],InStr([BUSINESS E-MAIL],";")-1),[BUSINESS E-MAIL]))<>"") AND (([Sales Header].[Document Type])=1) AND (([Sales Header].[ORDER TYPE])=0 Or ([Sales Header].[ORDER TYPE])=2));

